  ?competition wdt:P585 "2001-12-14"^^xsd:date .
  ?result wdt:P1638 ?competition .
  ?result wdt:P1145 "50.26" .
  ?competition wdt:P276 ?city
}

SELECT ?city WHERE {
  wd:Q1903905 wdt:P276 ?city .
  ?city wdt:P17 wd:Q31
}

